def evaluate_polynomial(poly, k):
 '''Evaluate chromatic polynomial at k'''
 result = 0
 for power, coeff in poly.items():
 result += coeff * (k ** power)
 return result

def find_chromatic_number(poly, max_k=20):
 '''Find chromatic number from chromatic polynomial'''
 for k in range(1, max_k + 1):
 if evaluate_polynomial(poly, k) > 0:
 return k
 return None

def print_polynomial(poly):
 '''Print polynomial in human-readable form'''
 terms = []
 for power in sorted(poly.keys(), reverse=True):
 coeff = poly[power]
 if coeff == 0:
 continue
 if power == 0:
 terms.append(str(coeff))
 elif power == 1:
 terms.append(f"{coeff}k")
 else:
 terms.append(f"{coeff}k^{power}")
 return " + ".join(terms).replace("+ -", "- ")

def chromatic_polynomial_path(n, k):
 '''Path graph P_n: k(k-1)^(n-1)'''
 return k * (k-1) ** (n-1)

def chromatic_polynomial_cycle(n, k):
 '''Cycle C_n: (k-1)^n + (-1)^n * (k-1)'''
 return (k-1)**n + ((-1)**n) * (k-1)

def chromatic_polynomial_complete(n, k):
 '''Complete graph K_n: k!/(k-n)! = falling factorial'''
 result = 1
 for i in range(n):
 result *= (k - i)
 return result

def chromatic_polynomial_tree(n, k):
 '''Tree with n vertices: k(k-1)^(n-1)'''
 return k * (k-1) ** (n-1)

def chromatic_polynomial_empty(n, k):
 '''Empty graph (n isolated vertices): k^n'''
 return k ** n

# Example usage
print("P(P4, 3) =", chromatic_polynomial_path(4, 3)) # 3*2^3 = 24
print("P(C5, 3) =", chromatic_polynomial_cycle(5, 3)) # 2^5 + 2 = 34
print("P(K4, 3) =", chromatic_polynomial_complete(4, 3)) # 0
print("P(T5, 3) =", chromatic_polynomial_tree(5, 3)) # 3*2^4 = 48
